/* ── Related Posts Section ── */

.rp-section {
    margin-top: 2.5rem;
    padding-top: 1.5rem;
    border-top: 1px solid var(--border-light);
    max-width: 620px;
    width: 100%;
    padding-left: 24px;
    padding-right: 24px;
    box-sizing: border-box;
}

.rp-heading {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    font-family: var(--font-ui);
    font-size: 0.68rem;
    font-weight: 700;
    letter-spacing: 0.08rem;
    text-transform: uppercase;
    color: var(--text-faint);
    margin: 0 0 1rem 0;
}

.rp-heading::after {
    content: '';
    flex: 1;
    height: 1px;
    background: var(--border-card);
}

/* ── Card Grid ── */

.rp-grid {
    display: flex;
    flex-direction: column;
    gap: 0.625rem;
}

/* ── Card ── */

.rp-card {
    display: flex;
    align-items: stretch;
    border-radius: 12px;
    background: var(--bg-card);
    border: 1px solid var(--border-card);
    cursor: pointer;
    overflow: hidden;
    transition: box-shadow 0.25s ease, transform 0.25s ease, border-color 0.25s ease;
}

.rp-card:hover {
    box-shadow: 0 4px 18px rgba(0, 0, 0, 0.06);
    transform: translateY(-1px);
    border-color: rgba(212, 168, 83, 0.2);
}

/* ── Accent Line ── */

.rp-card-accent {
    width: 3.5px;
    flex-shrink: 0;
    background: linear-gradient(180deg, var(--accent-purple), rgba(196, 148, 62, 0.5));
    border-radius: 3px 0 0 3px;
    transition: opacity 0.3s ease;
}

/* ── Card Content ── */

.rp-card-content {
    flex: 1;
    padding: 0.75rem 0.875rem;
    min-width: 0;
}

